SET client_encoding TO 'UTF8';

SET check_function_bodies = false;





CREATE OR REPLACE FUNCTION fpb_amn_req_diff ( as_reqno text ) RETURNS bigint AS $body$
DECLARE

ldc_diff  bigint;
ldc_new bigint;
ldc_old bigint;

BEGIN

    select period_payment_amount  into STRICT ldc_new
    from sc_lon_m_loan_request
    where 1=1
    and loan_requestment_no =  as_reqno
;

    select coalesce( sum( payment_amount ), 0 ) into STRICT ldc_old
    from sc_lon_m_loan_history
    where 1=1
    and clear_target = '1'
    and loan_requestment_no = as_reqno
    
;

    ldc_diff := ldc_new - ldc_old;

    return ldc_diff;

exception when others then CALL spa_dberror('FPB_AMN_REQ_DIFF');
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
